import{_ as e,o as t,c as o,ak as l}from"./chunks/framework.d_5_XLDx.js";const m=JSON.parse('{"title":"⚠️【机场跑路】2025年2月11日SFCloud与FCCloud机场跑路","description":"","frontmatter":{"title":"⚠️【机场跑路】2025年2月11日SFCloud与FCCloud机场跑路","createTime":"2025/02/11 07:48:36","permalink":"/article/7asq3quy/","tags":["科学上网","VPN","机场","跑路","预警","SFCloud","FCCloud"]},"headers":[],"relativePath":"blog/ermao/跑路机场/SFCloud和FCCloud.md","filePath":"blog/ermao/跑路机场/SFCloud和FCCloud.md","lastUpdated":1769776243000}'),r={name:"blog/ermao/跑路机场/SFCloud和FCCloud.md"};function s(d,a,i,p,n,c){return t(),o("div",null,[...a[0]||(a[0]=[l('<p>2025年2月11日，SFCloud与FCCloud官方确认已跑路。官网无法访问，节点全挂，工单不回复。</p><p><strong>立即停止续费，避免更大损失！</strong></p><p>目前，<s>XSUS</s> 表示可以接手SFCloud和FCCloud用户（按原订阅30%接收），详情请在<s>XSUS 官网</s> 注册后提交工单咨询。</p><div class="custom-block warning"><p class="custom-block-title">警告</p><p>2025年4月28日 XSUS 已触发跑路预警，不建议使用XSUS机场。</p></div><p>在选择机场时，推荐选择一些老牌机场（如<a href="https://ermao.dgywzc.com/#/register?code=peAVAa8D" target="_blank" rel="noreferrer">大哥云</a>），这样可以有效减少跑路的风险。</p><h2 id="推测" tabindex="-1">推测 <a class="header-anchor" href="#推测" aria-label="Permalink to &quot;推测&quot;">​</a></h2><p>SFCloud 与 FCCloud 起初由 EFCloud 引流，如今 EFcloud 已经于 2025年1月25日跑路，SFCloud 和 FCCloud 大概率跑路！</p><p>相关文章：<a href="/article/nz313xp6/">⚠️【机场跑路】2025年1月25日EFCloud机场跑路</a></p><h2 id="fccloud-节点无法使用截图" tabindex="-1">FCCloud 节点无法使用截图 <a class="header-anchor" href="#fccloud-节点无法使用截图" aria-label="Permalink to &quot;FCCloud 节点无法使用截图&quot;">​</a></h2><p><img src="https://image.ermao.net/images/article/7asq3quy/image.png" alt="FCCloud 跑路"></p><p><img src="https://image.ermao.net/images/article/7asq3quy/image-1.png" alt="FCCloud 跑路"></p><h2 id="网友预警" tabindex="-1">网友预警 <a class="header-anchor" href="#网友预警" aria-label="Permalink to &quot;网友预警&quot;">​</a></h2><p><img src="https://image.ermao.net/images/article/7asq3quy/image-2.png" alt="FCCloud 跑路"></p><p><img src="https://image.ermao.net/images/article/7asq3quy/image-3.png" alt="FCCloud 跑路"></p><h2 id="机场跑路-预警-投稿" tabindex="-1">机场跑路（预警）投稿 <a class="header-anchor" href="#机场跑路-预警-投稿" aria-label="Permalink to &quot;机场跑路（预警）投稿&quot;">​</a></h2><p><a href="https://pyjichang.com/scamvpn/" target="_blank" rel="noreferrer">点击投稿</a></p><h2 id="其他推荐机场" tabindex="-1">其他推荐机场 <a class="header-anchor" href="#其他推荐机场" aria-label="Permalink to &quot;其他推荐机场&quot;">​</a></h2><div class="custom-block warning"><p class="custom-block-title">警告</p><p>任何机场都有跑路的风险，建议备份几个按流量付费机场防止失联，同时主力机场使用月付费，尽可能减少损失。</p></div><p><a href="https://www.ermao.net/posts/vpn" target="_blank" rel="noreferrer">https://www.ermao.net/posts/vpn</a></p>',19)])])}const C=e(r,[["render",s]]);export{m as __pageData,C as default};
